1	export type Cell = [number, number];
2	
3	const cellKey = (x: number, y: number): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [0, -1],           [0, 1],
8	  [1, -1],  [1, 0],  [1, 1],
9	];
10	
11	export const nextGeneration = (cells: Cell[]): Cell[] => {
12	  const aliveKeys = new Set(cells.map(([x, y]) => cellKey(x, y)));
13	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
14	
15	  for (const [x, y] of cells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const neighbor: Cell = [x + dx, y + dy];
18	      const k = cellKey(neighbor[0], neighbor[1]);
19	      const entry = neighborCounts.get(k);
20	      if (entry) entry.count += 1;
21	      else neighborCounts.set(k, { cell: neighbor, count: 1 });
22	    }
23	  }
24	
25	  const survives = (k: string, count: number): boolean =>
26	    count === 3 || (count === 2 && aliveKeys.has(k));
27	
28	  return [...neighborCounts]
29	    .filter(([k, { count }]) => survives(k, count))
30	    .map(([, { cell }]) => cell);
31	};
32

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns empty array when given empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("keeps a block (still life) unchanged - 2x2 stable pattern", () => {
15	    const block: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("transforms vertical blinker to horizontal blinker", () => {
20	    const vertical: Array<[number, number]> = [[0, 0], [0, 1], [0, 2]];
21	    const expected: Array<[number, number]> = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect(result.sort()).toEqual(expected.sort());
24	  });
25	  it("kills center cell with 4 neighbors (overpopulation)", () => {
26	    // Center (1,1) has 4 corner neighbors → dies from overpopulation.
27	    const input: Array<[number, number]> = [[0, 0], [2, 0], [1, 1], [0, 2], [2, 2]];
28	    const result = nextGeneration(input);
29	    expect(result).not.toContainEqual([1, 1]);
30	  });
31	  it("brings a dead cell to life when it has exactly 3 neighbors (reproduction)", () => {
32	    // L-shape: (0,0),(1,0),(0,1). Dead cell (1,1) has 3 live neighbors → becomes alive.
33	    const input: Array<[number, number]> = [[0, 0], [1, 0], [0, 1]];
34	    const result = nextGeneration(input);
35	    expect(result).toContainEqual([1, 1]);
36	  });
37	});
