export const nextGeneration = (cells: Cell[]): Cell[] => {
  const aliveKeys = new Set(cells.map(([x, y]) => cellKey(x, y)));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const k = cellKey(neighbor[0], neighbor[1]);
      const entry = neighborCounts.get(k);
      if (entry) entry.count += 1;
      else neighborCounts.set(k, { cell: neighbor, count: 1 });
    }
  }

  const survives = (k: string, count: number): boolean =>
    count === 3 || (count === 2 && aliveKeys.has(k));

  return [...neighborCounts]
    .filter(([k, { count }]) => survives(k, count))
    .map(([, { cell }]) => cell);
};

